INSERT INTO app_settings(id, settings) VALUES (1, '{"vat_rate": 0.22, "k1": 0.65, "payroll_tax_rate": 0.3, "diesel_l_per_100km": 12.0, "office_cities": ["Казань", "Москва"], "office_rates": {"Казань": {"driver_km_rate": 15.0, "cryoblaster_rate": 4000.0, "gazelle_rate": 10.0, "sale_st": 0.565}, "Москва": {"driver_km_rate": 18.0, "cryoblaster_rate": 4500.0, "gazelle_rate": 12.0, "sale_st": 0.465}}, "font_family": "Arial", "ui": {"action_list_width_pct": 31, "font_base_px": 13, "font_title_px": 18, "card_padding_px": 10, "field_gap_px": 8, "table_row_height_px": 30, "criteria_name_width_pct": 20, "criteria_levels_width_pct": 60, "criteria_comment_width_pct": 20}, "criteria": [{"block": "P", "code": "P1", "title": "Покупающий центр подтвержден", "desc": "Кто со стороны клиента участвует в демонстрации и согласовании.", "levels": [["Участники не подтверждены", 0], ["Только пользователь / мастер", 5], ["Есть технический инициатор", 10], ["Есть руководитель / ЛПР и технический инициатор", 15]]}, {"block": "P", "code": "P2", "title": "Объект очистки определен", "desc": "Есть ли конкретный объект, который будут чистить.", "levels": [["Объект не выбран", 0], ["Объект назван устно", 5], ["Объект назван и есть фото / видео", 10], ["Объект назван, есть фото / видео и клиент подтвердил его приоритет", 15]]}, {"block": "P", "code": "P3", "title": "Загрязнение и текущий метод очистки описаны", "desc": "Понятно ли, что удалить и чем клиент чистит сейчас.", "levels": [["Загрязнение не описано", 0], ["Описано только загрязнение", 4], ["Описаны загрязнение и текущий метод", 7], ["Описаны загрязнение, текущий метод и проблемы текущего метода", 10]]}, {"block": "P", "code": "P4", "title": "Воздух и площадка подтверждены", "desc": "Готовность пневмосети и места проведения.", "levels": [["Данные по воздуху отсутствуют", 0], ["Подтверждено только давление", 5], ["Подтверждены давление и расход", 10], ["Подтверждены давление, расход, подключение, доступ и безопасность", 15]]}, {"block": "P", "code": "P5", "title": "Критерии успеха согласованы", "desc": "Договорились ли заранее, что считается успешной демонстрацией.", "levels": [["Критерии не согласованы", 0], ["Есть устное ожидание результата", 5], ["Согласованы качество и время очистки", 10], ["Согласованы качество, время, расход льда и способ фиксации результата", 15]]}, {"block": "P", "code": "P6", "title": "Коммерческий потенциал понятен", "desc": "Есть ли связь между демонстрацией и будущей продажей.", "levels": [["Коммерческий потенциал не понятен", 0], ["Есть общий интерес", 5], ["Понятна возможная модель или бюджет", 10], ["Понятны модель, бюджет, срок и следующий шаг", 15]]}, {"block": "P", "code": "P7", "title": "Логистика и бюджет выезда согласованы", "desc": "Подготовлены ли маршрут, лед, транспорт, люди и бюджет.", "levels": [["Логистика не согласована", 0], ["Согласованы маршрут и участники", 5], ["Согласованы маршрут, участники, лед, транспорт и бюджет", 10]]}, {"block": "P", "code": "P8", "title": "Карточка подготовки заполнена", "desc": "Формальный критерий дисциплины. Без карточки нельзя доказать подготовку.", "levels": [["Карточка отсутствует", 0], ["Карточка заполнена частично", 3], ["Карточка заполнена полностью", 5]]}, {"block": "R", "code": "R1", "title": "Согласованный технический результат достигнут", "desc": "Достигнута ли цель очистки, согласованная до демонстрации.", "levels": [["Результат не достигнут", 0], ["Результат достигнут частично", 8], ["Результат достигнут полностью", 15], ["Результат достигнут лучше согласованных критериев", 20]]}, {"block": "R", "code": "R2", "title": "Измерения зафиксированы", "desc": "Есть ли цифры: время, расход льда, давление, сопло, площадь / деталь.", "levels": [["Измерений нет", 0], ["Есть только фото / видео", 5], ["Есть время или расход льда", 10], ["Есть время, расход льда, давление, сопло и площадь / деталь", 15]]}, {"block": "R", "code": "R3", "title": "Клиент подтвердил результат", "desc": "Кто со стороны клиента увидел и подтвердил результат.", "levels": [["Подтверждения клиента нет", 0], ["Подтвердил пользователь / мастер", 5], ["Подтвердил технический инициатор", 10], ["Подтвердил руководитель / ЛПР или главный инженер", 15]]}, {"block": "R", "code": "R4", "title": "Следующий шаг после демонстрации получен", "desc": "КП, счет, аренда, договор или повторный тест.", "levels": [["Следующего шага нет", 0], ["Есть только устный интерес", 5], ["Назначена дата следующего контакта / встречи", 12], ["Запрошены КП, счет, аренда, договор или повторный тест", 20]]}, {"block": "R", "code": "R5", "title": "Отчет по демонстрации оформлен", "desc": "Отчет для клиента и контроля ИРБИСТЕХ.", "levels": [["Отчета нет", 0], ["Есть краткий отчет с фото / видео", 5], ["Есть отчет с фото / видео, цифрами и выводом", 10]]}, {"block": "R", "code": "R6", "title": "Экономика для клиента посчитана", "desc": "Технический результат переведен в часы, рубли или человеко-часы.", "levels": [["Экономика не обсуждалась", 0], ["Есть оценка эффекта словами", 5], ["Есть расчет в часах, рублях или человеко-часах", 10]]}, {"block": "R", "code": "R7", "title": "Причина неуспеха или отказа зафиксирована", "desc": "Если нет продажи, понятно почему и что делать дальше.", "levels": [["Причина не зафиксирована", 0], ["Причина описана устно", 5], ["Причина зафиксирована письменно и есть дальнейшее решение", 10]]}, {"block": "M", "code": "M1", "title": "Стратегический статус клиента подтвержден", "desc": "Крупный клиент, отраслевой лидер, повторные продажи, публичный кейс.", "levels": [["Стратегический статус не подтвержден", 0], ["Статус подтвержден руководителем продаж", 8], ["Статус подтвержден директором до выезда", 15]]}, {"block": "M", "code": "M2", "title": "Клиент участвует в расходах", "desc": "Оплата или организационное участие клиента подтверждает серьезность намерений.", "levels": [["Клиент не участвует", 0], ["Клиент предоставляет только площадку / людей", 5], ["Клиент оплачивает часть расходов", 12], ["Клиент оплачивает демонстрацию полностью или почти полностью", 20]]}, {"block": "M", "code": "M3", "title": "Выезд заранее согласован внутри ИРБИСТЕХ", "desc": "Кто разрешил тратить деньги на демонстрацию.", "levels": [["Выезд не согласован заранее", 0], ["Выезд согласован с руководителем продаж", 8], ["Выезд согласован директором до начала расходов", 15]]}, {"block": "M", "code": "M4", "title": "Логистика выезда оптимизирована", "desc": "Расходы распределяются на несколько задач маршрута.", "levels": [["Отдельный выезд только под одного клиента", 0], ["Выезд частично совмещен с другой задачей", 5], ["В маршруте 2+ демонстрации / задачи", 10]]}, {"block": "M", "code": "M5", "title": "Повторная демонстрация обоснована", "desc": "Повтор по запросу клиента отличается от повтора из-за ошибки подготовки.", "levels": [["Повтор из-за ошибки подготовки", 0], ["Первая демонстрация или повтор не требуется", 7], ["Повтор по запросу клиента после успешной демонстрации", 10]]}, {"block": "M", "code": "M6", "title": "Демонстрация дала маркетинговую или R&D-ценность", "desc": "Фото, видео, новый кейс, новая отрасль, проверка новой задачи.", "levels": [["Материалы непригодны для повторного использования", 0], ["Материалы пригодны только внутри компании", 7], ["Материалы пригодны для кейса / обучения / R&D", 15]]}, {"block": "M", "code": "M7", "title": "Ответственность за отклонения и перерасход", "desc": "Защита от снижения вычета, если перерасход возник по вине менеджера.", "levels": [["Отклонение возникло по вине менеджера", 0], ["Отклонений не было", 10], ["Отклонение возникло по подтвержденной причине вне зоны ответственности менеджера", 15]]}], "expense_settings": [{"article": "Работа водителя за километраж по маячку А5/А6", "section": "driver", "unit": "км", "qty_default": 300, "price_net_default": 0, "price_vat_default": 0, "qty_manager": true, "price_manager": false, "calc_type": "office_driver_km", "comment": "Количество вводит менеджер; ставка подставляется по офису менеджера"}, {"article": "Работа демонстратора", "section": "driver", "unit": "ч", "qty_default": 8, "price_net_default": 1350, "price_vat_default": 0, "qty_manager": false, "price_manager": false, "calc_type": "demo_hours", "comment": "Количество равно полю «Время работы демонстратором»"}, {"article": "Демонстрация криобластера", "section": "driver", "unit": "ч", "qty_default": 8, "price_net_default": 0, "price_vat_default": 0, "qty_manager": false, "price_manager": false, "calc_type": "office_cryoblaster", "comment": "Ставка подставляется по офису менеджера"}, {"article": "Налоги на ФОТ", "section": "driver", "unit": "усл", "qty_default": 1, "price_net_default": 0, "price_vat_default": 0, "qty_manager": false, "price_manager": false, "calc_type": "payroll_tax", "comment": "Автоматически от сумм ГПХ/ПНД"}, {"article": "Расходы на отель Менеджера", "section": "other", "unit": "день × чел", "qty_default": 1, "price_net_default": 2800, "price_vat_default": 0, "qty_manager": true, "price_manager": true, "calc_type": "direct", "comment": "Менеджерское поле"}, {"article": "Расходы на отель Водителя", "section": "other", "unit": "день × чел", "qty_default": 1, "price_net_default": 2800, "price_vat_default": 0, "qty_manager": true, "price_manager": true, "calc_type": "direct", "comment": "Менеджерское поле"}, {"article": "Расходы на переезд менеджера", "section": "other", "unit": "усл", "qty_default": 0, "price_net_default": 3000, "price_vat_default": 0, "qty_manager": true, "price_manager": true, "calc_type": "direct", "comment": "Менеджерское поле"}, {"article": "Расходы на платную дорогу", "section": "other", "unit": "усл", "qty_default": 0, "price_net_default": 0, "price_vat_default": 0, "qty_manager": true, "price_manager": true, "calc_type": "direct", "comment": "Менеджерское поле"}, {"article": "Суточные для командировки", "section": "other", "unit": "день × чел", "qty_default": 2, "price_net_default": 1500, "price_vat_default": 0, "qty_manager": false, "price_manager": false, "calc_type": "dir